package com.kalyani.car_rental_backend.review.controller;import com.kalyani.car_rental_backend.booking.entity.BookingStatus;import com.kalyani.car_rental_backend.booking.repository.BookingRepository;import com.kalyani.car_rental_backend.exception.ResourceNotFoundException;import com.kalyani.car_rental_backend.response.ApiResponse;import com.kalyani.car_rental_backend.review.dto.ReviewRequest;import com.kalyani.car_rental_backend.review.entity.Review;import com.kalyani.car_rental_backend.review.repository.ReviewRepository;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/reviews")public class ReviewController{private final ReviewRepository repo;private final BookingRepository bookings;public ReviewController(ReviewRepository r,BookingRepository b){repo=r;bookings=b;}@PostMapping public ResponseEntity<ApiResponse<Map<String,Object>>> create(@Valid @RequestBody ReviewRequest r,Authentication a){var b=bookings.findById(r.bookingId).orElseThrow(()->new ResourceNotFoundException("Booking not found"));if(!b.getUser().getEmail().equalsIgnoreCase(a.getName()))throw new IllegalArgumentException("You can review only your booking");if(b.getStatus()!=BookingStatus.COMPLETED)throw new IllegalArgumentException("Review is allowed after trip completion");if(repo.existsByBookingId(b.getId()))throw new IllegalArgumentException("Review already submitted");var e=new Review();e.setBooking(b);e.setUser(b.getUser());e.setRating(r.rating);e.setComment(r.comment);return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(out(repo.save(e)),"Review submitted"));}@GetMapping("/car/{carId}")public ResponseEntity<ApiResponse<List<Map<String,Object>>>> car(@PathVariable Long carId){return ResponseEntity.ok(ApiResponse.success(repo.findByBookingCarIdOrderByCreatedAtDesc(carId).stream().map(this::out).toList(),"Reviews loaded"));}private Map<String,Object>out(Review r){Map<String,Object>m=new LinkedHashMap<>();m.put("id",r.getId());m.put("bookingId",r.getBooking().getId());m.put("userName",r.getUser().getFullName());m.put("rating",r.getRating());m.put("comment",r.getComment());m.put("createdAt",r.getCreatedAt());return m;}}
